+fn btrfs_name_len_u16(len: usize, field: &'static str) -> Result<u16, ParseError> {
+    u16::try_from(len).map_err(|_| ParseError::InvalidField {
+        field,
+        reason: "name length exceeds u16::MAX",
+    })
